def least_frequent_word(s):
    if not s:
        return ''

    words = s.split()
    word_counts = {}

    for word in words:
        lower_word = word.lower()
        if lower_word in word_counts:
            word_counts[lower_word] += 1
        else:
            word_counts[lower_word] = 1

    min_count = min(word_counts.values())
    least_frequent_words = [word for word, count in word_counts.items() if count == min_count]

    return sorted(least_frequent_words)[0]
